import React, { useState, useCallback } from 'react';
import { useLocation, useHistory } from 'react-router-dom';

const AddVendor = () => {
  const [newVendor, setNewVendor] = useState({
    name: '',
    field: '',
    mail: '',
    tel: '',
    contactname: ''
    // Add additional fields as needed for the vendor
  });



  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewVendor((prevVendor) => ({
      ...prevVendor,
      [name]: value,
    }));
  };

  const handleAddVendor = useCallback((newVendor) => {
    // Send an HTTP request to add the new vendor
    fetch('http://localhost:8081/vendors', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newVendor),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding vendor');
        }
      })
      .then(() => {
        // Refresh the vendors list
        fetch('http://localhost:8081/vendors')
          .then((response) => response.json())
          .then((vendorResponse) => {
            // Handle the response, e.g., set the vendors state
          })
          .catch((error) => {
            console.log('Error fetching vendors:', error);
          });
      })
      .catch((error) => {
        console.log('Error adding vendor:', error);
      });
  }, []);

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAddVendor(newVendor);
    resetForm();
  };

  const resetForm = () => {
    setNewVendor({
      name: '',
      field: '',
      mail: '',
      tel: '',
      contactname: ''
      // Reset additional fields as needed for the vendor
    });
  };

  return (
    <div className="add-vendor-container">
      <h2 className="add-vendor-heading">Add Vendor</h2>
      <form className="add-vendor-form" onSubmit={handleSubmit}>
        <label>
          Vendor Name:
          <input
            type="text"
            name="name"
            value={newVendor.name}
            onChange={handleInputChange}
          />
        </label>
        <label>
          Field:
          <input
            type="text"
            name="field"
            value={newVendor.field}
            onChange={handleInputChange}
          />
        </label>
        <label>
          Email:
          <input
            type="email"
            name="mail"
            value={newVendor.mail}
            onChange={handleInputChange}
          />
        </label>
        <label>
          Telephone:
          <input
            type="tel"
            name="tel"
            value={newVendor.tel}
            onChange={handleInputChange}
          />
        </label>
        <label>
          Contact Name:
          <input
            type="text"
            name="contactname"
            value={newVendor.contactname}
            onChange={handleInputChange}
          />
        </label>
        <button type="submit">Add Vendor</button>
      </form>
    </div>
  );
};

export default AddVendor;
